const headers = $json.headers || {};
const query = $json.query || {};
const expected = $env.KGANYA_STATUS_API_TOKEN;
const auth = headers.authorization || headers.Authorization || headers['x-kganya-console-token'] || '';
const token = auth.replace(/^Bearer\s+/i, '').trim();
if (!expected || token !== expected) throw new Error('UNAUTHENTICATED');
return [{ json: { authValid: true, organizationId: query.organizationId || null, batchId: query.batchId || null, sourceRecordId: query.sourceRecordId || null, state: query.state || null, page: Number(query.page || 1), pageSize: Math.min(Number(query.pageSize || 25), 100) } }];

const rows = $input.all().map((item) => item.json ?? item);
const filter = $node["Build Status Filter"].json;
return [{ json: { organizationId: filter.organizationId || null, batchId: filter.batchId || null, sourceRecordId: filter.sourceRecordId || null, page: filter.page || 1, pageSize: filter.pageSize || 25, states: rows } }];
